import java.io.File;
import java.io.FileWriter;
import java.io.IOException;
import org.apache.commons.text.StringEscapeUtils;

public class XSSSecureCode {
    public static void main(String[] args) {
        // Simulating user input from a form field
        String userInput = "<script>alert('XSS Vulnerability!')</script>";

        // Properly encoding user input to prevent XSS
        String output = "<p>Welcome, " + StringEscapeUtils.escapeHtml4(userInput) + "</p>";

        try {
            // Outputting the user input to the web page
            File file = new File("output.html");
            FileWriter writer = new FileWriter(file);
            writer.write(output);
            writer.close();

            System.out.println("Output written to output.html");
        } catch (IOException e) {
            e.printStackTrace();
        }
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
